    61→// VersionPassesFilter returns true if the version string passes the source's
    62→// include/exclude regex filters. When both are nil the version always passes.
    63→func VersionPassesFilter(version string, include, exclude *string) bool {
    64→	if include != nil && *include != "" {
    65→		matched, err := regexp.MatchString(*include, version)
    66→		if err != nil || !matched {
    67→			return false
    68→		}
    69→	}
    70→	if exclude != nil && *exclude != "" {
    71→		matched, err := regexp.MatchString(*exclude, version)
    72→		if err != nil || matched {
    73→			return false
    74→		}
    75→	}
    76→	return true
    77→}
