   559→func (s *PgStore) ListSubscriptions(ctx context.Context, page, perPage int) ([]models.Subscription, int, error) {
   560→	var total int
   561→	err := s.pool.QueryRow(ctx, `SELECT COUNT(*) FROM subscriptions`).Scan(&total)
   562→	if err != nil {
   563→		return nil, 0, fmt.Errorf("count subscriptions: %w", err)
   564→	}
   565→	offset := (page - 1) * perPage
   566→	rows, err := s.pool.Query(ctx,
   567→		`SELECT id, channel_id, type, source_id, project_id, COALESCE(version_filter,''), created_at
   568→		 FROM subscriptions ORDER BY created_at DESC LIMIT $1 OFFSET $2`, perPage, offset)
   569→	if err != nil {
   570→		return nil, 0, fmt.Errorf("list subscriptions: %w", err)
   571→	}
   572→	defer rows.Close()
   573→	var subs []models.Subscription
   574→	for rows.Next() {
   575→		var sub models.Subscription
   576→		if err := rows.Scan(&sub.ID, &sub.ChannelID, &sub.Type, &sub.SourceID,
   577→			&sub.ProjectID, &sub.VersionFilter, &sub.CreatedAt); err != nil {
   578→			return nil, 0, fmt.Errorf("scan subscription: %w", err)
   579→		}
   580→		subs = append(subs, sub)
   581→	}
   582→	return subs, total, nil
   583→}
