   585→func (s *PgStore) CreateSubscription(ctx context.Context, sub *models.Subscription) error {
   586→	return s.pool.QueryRow(ctx,
   587→		`INSERT INTO subscriptions (channel_id, type, source_id, project_id, version_filter)
   588→		 VALUES ($1, $2, $3, $4, $5)
   589→		 RETURNING id, created_at`,
   590→		sub.ChannelID, sub.Type, sub.SourceID, sub.ProjectID, sub.VersionFilter,
   591→	).Scan(&sub.ID, &sub.CreatedAt)
   592→}
   593→
   594→func (s *PgStore) CreateSubscriptionBatch(ctx context.Context, subs []models.Subscription) ([]models.Subscription, error) {
   595→	tx, err := s.pool.Begin(ctx)
   596→	if err != nil {
   597→		return nil, fmt.Errorf("begin tx: %w", err)
   598→	}
   599→	defer tx.Rollback(ctx)
   600→
   601→	var result []models.Subscription
   602→	for i := range subs {
   603→		sub := subs[i]
   604→		err := tx.QueryRow(ctx,
   605→			`INSERT INTO subscriptions (channel_id, type, source_id, project_id, version_filter)
   606→			 VALUES ($1, $2, $3, $4, $5)
   607→			 RETURNING id, created_at`,
