  1034→// EnqueueAgentRun creates an agent_run row and enqueues a River AgentJobArgs.
  1035→// This follows the transactional outbox pattern for zero-loss guarantee.
  1036→func (s *PgStore) EnqueueAgentRun(ctx context.Context, projectID, trigger, version string) error {
  1037→	tx, err := s.pool.Begin(ctx)
  1038→	if err != nil {
  1039→		return fmt.Errorf("begin tx: %w", err)
  1040→	}
  1041→	defer tx.Rollback(ctx)
  1042→
  1043→	var runID string
  1044→	err = tx.QueryRow(ctx,
  1045→		`INSERT INTO agent_runs (project_id, trigger, version, status)
  1046→		 VALUES ($1, $2, $3, 'pending')
  1047→		 RETURNING id`, projectID, trigger, version,
  1048→	).Scan(&runID)
  1049→	if err != nil {
  1050→		return fmt.Errorf("insert agent run: %w", err)
  1051→	}
  1052→
  1053→	if s.river != nil {
  1054→		_, err = s.river.InsertTx(ctx, tx, queue.AgentJobArgs{
  1055→			AgentRunID: runID,
  1056→			ProjectID:  projectID,
  1057→			Version:    version,
  1058→		}, nil)
  1059→		if err != nil {
  1060→			return fmt.Errorf("enqueue agent job: %w", err)
  1061→		}
  1062→	}
  1063→
  1064→	return tx.Commit(ctx)
  1065→}
