package routing

import (
	"context"
	"encoding/json"
	"fmt"
	"log/slog"
	"net/http"
	"regexp"
	"strings"
	"time"

	"github.com/riverqueue/river"
	"github.com/sentioxyz/changelogue/internal/models"
	"github.com/sentioxyz/changelogue/internal/queue"
)

// NotifyStore is the data access interface required by the notification worker.
type NotifyStore interface {
	GetRelease(ctx context.Context, id string) (*models.Release, error)
	GetSource(ctx context.Context, id string) (*models.Source, error)
	ListSourceSubscriptions(ctx context.Context, sourceID string) ([]models.Subscription, error)
	GetChannel(ctx context.Context, id string) (*models.NotificationChannel, error)
	GetProject(ctx context.Context, id string) (*models.Project, error)
	GetPreviousRelease(ctx context.Context, sourceID string, beforeVersion string) (*models.Release, error)
	EnqueueAgentRun(ctx context.Context, projectID, trigger, version string) error
	CreateReleaseTodo(ctx context.Context, releaseID string) (string, error)
}

// NotifyWorker is a River worker that processes NotifyJobArgs.
// It looks up the release, finds all source-level subscriptions, resolves
// the notification channel for each, and dispatches via the appropriate sender.
// After sending notifications, it checks the project's agent rules and
// auto-triggers an agent run if the version criteria are met.
type NotifyWorker struct {
	river.WorkerDefaults[queue.NotifyJobArgs]
	store     NotifyStore
	senders   map[string]Sender
	publicURL string // base URL for internal Changelogue links (e.g. "https://changelogue.example.com")
}

// NewSenders returns the default sender map for all notification channel types.
func NewSenders() map[string]Sender {
	return map[string]Sender{
		"webhook": &WebhookSender{Client: &http.Client{Timeout: 10 * time.Second}},
		"slack":   &SlackSender{Client: &http.Client{Timeout: 10 * time.Second}},
		"discord": &DiscordSender{Client: &http.Client{Timeout: 10 * time.Second}},
		"email":   &EmailSender{},
	}
}

// NewNotifyWorker creates a NotifyWorker with default senders for webhook, Slack, and Discord.
func NewNotifyWorker(store NotifyStore, publicURL string) *NotifyWorker {
	return &NotifyWorker{
		store:     store,
		senders:   NewSenders(),
		publicURL: strings.TrimRight(publicURL, "/"),
	}
}

// VersionPassesFilter returns true if the version string passes the source's
// include/exclude regex filters. When both are nil the version always passes.
func VersionPassesFilter(version string, include, exclude *string) bool {
	if include != nil && *include != "" {
		matched, err := regexp.MatchString(*include, version)
		if err != nil || !matched {
			return false
		}
	}
	if exclude != nil && *exclude != "" {
		matched, err := regexp.MatchString(*exclude, version)
		if err != nil || matched {
			return false
		}
	}
	return true
}

// Work processes a notify job: fetches the release, resolves subscriptions,
// sends notifications to all matching channels, and checks agent rules to
// auto-trigger agent runs when version criteria are met.
func (w *NotifyWorker) Work(ctx context.Context, job *river.Job[queue.NotifyJobArgs]) error {
	release, err := w.store.GetRelease(ctx, job.Args.ReleaseID)
	if err != nil {
		return fmt.Errorf("get release: %w", err)
	}

	// Check source version filters — skip entirely if filtered out.
	source, err := w.store.GetSource(ctx, job.Args.SourceID)
	if err != nil {
		return fmt.Errorf("get source: %w", err)
	}
	if !VersionPassesFilter(release.Version, source.VersionFilterInclude, source.VersionFilterExclude) {
		slog.Debug("release filtered by version filter", "version", release.Version, "source_id", job.Args.SourceID)
		return nil
	}

	// Check exclude_prereleases — skip if source excludes prereleases and this is one.
	if source.ExcludePrereleases {
		var rawData map[string]interface{}
		if err := json.Unmarshal(release.RawData, &rawData); err == nil {
			if prerelease, _ := rawData["prerelease"].(string); prerelease == "true" {
				slog.Debug("release filtered by exclude_prereleases", "version", release.Version, "source_id", job.Args.SourceID)
				return nil
			}
		}
	}

	// Create a TODO for this release (idempotent — safe for retries).
	todoID, todoErr := w.store.CreateReleaseTodo(ctx, release.ID)
	if todoErr != nil {
		slog.Error("create release todo failed", "release_id", release.ID, "err", todoErr)
		// Continue — notification delivery is primary responsibility.
	}

	subs, err := w.store.ListSourceSubscriptions(ctx, job.Args.SourceID)
	if err != nil {
		return fmt.Errorf("list subscriptions: %w", err)
	}

	for _, sub := range subs {
		ch, err := w.store.GetChannel(ctx, sub.ChannelID)
		if err != nil {
			slog.Error("get channel failed", "channel_id", sub.ChannelID, "err", err)
			continue
		}

		sender, ok := w.senders[ch.Type]
		if !ok {
			slog.Warn("unknown channel type", "type", ch.Type)
			continue
		}

		// Build title with project name if available.
		title := release.Version
		if release.ProjectName != "" {
			title = release.ProjectName
		}

		msg := Notification{
			Title:       title,
			Body:        string(release.RawData),
			Version:     release.Version,
			ProjectName: release.ProjectName,
			Provider:    release.Provider,
			Repository:  release.Repository,
			SourceURL:   ProviderURL(release.Provider, release.Repository, release.Version),
		}
		if w.publicURL != "" {
			msg.ReleaseURL = fmt.Sprintf("%s/releases/%s", w.publicURL, release.ID)
		}
		if todoID != "" {
			msg.TodoID = todoID
			msg.PublicURL = w.publicURL
		}

		if err := sender.Send(ctx, ch, msg); err != nil {
			slog.Error("send notification failed", "channel", ch.Name, "err", err)
		}
	}

	// Check agent rules and auto-trigger if criteria are met.
	w.checkAgentRules(ctx, release, source)

	return nil
}

// checkAgentRules evaluates the project's agent rules against the new release
// and the previous release for this source. If any rule matches, an agent run
// is enqueued. Errors are logged but do not fail the job — notification delivery
// is the primary responsibility.
func (w *NotifyWorker) checkAgentRules(ctx context.Context, release *models.Release, source *models.Source) {
	project, err := w.store.GetProject(ctx, source.ProjectID)
	if err != nil {
		slog.Error("get project for agent rules", "project_id", source.ProjectID, "err", err)
		return
	}

	// Parse the project's agent_rules JSON.
	var rules models.AgentRules
	if len(project.AgentRules) > 0 {
		if err := json.Unmarshal(project.AgentRules, &rules); err != nil {
			slog.Error("unmarshal agent rules", "project_id", project.ID, "err", err)
			return
		}
	}

	// Determine the previous version for comparison.
	var previousVersion string
	prev, err := w.store.GetPreviousRelease(ctx, source.ID, release.Version)
	if err != nil {
		slog.Error("get previous release for agent rules", "source_id", source.ID, "err", err)
		return
	}
	if prev != nil {
		previousVersion = prev.Version
	}

	if CheckAgentRules(&rules, release.Version, previousVersion) {
		trigger := fmt.Sprintf("auto:version:%s", release.Version)
		if err := w.store.EnqueueAgentRun(ctx, source.ProjectID, trigger, release.Version); err != nil {
			slog.Error("enqueue agent run", "project_id", source.ProjectID, "err", err)
		} else {
			slog.Info("agent run triggered by version rules",
				"project_id", source.ProjectID,
				"version", release.Version,
				"previous_version", previousVersion,
			)
		}
	}
}

package main

import (
	"context"
	"log/slog"
	"net/http"
	"os"
	"os/signal"
	"time"

	"github.com/riverqueue/river"
	agentpkg "github.com/sentioxyz/changelogue/internal/agent"
	"github.com/sentioxyz/changelogue/internal/api"
	"github.com/sentioxyz/changelogue/internal/auth"
	"github.com/sentioxyz/changelogue/internal/db"
	"github.com/sentioxyz/changelogue/internal/ingestion"
	"github.com/sentioxyz/changelogue/internal/onboard"
	"github.com/sentioxyz/changelogue/internal/queue"
	"github.com/sentioxyz/changelogue/internal/routing"
)

func main() {
	// Configure log level from LOG_LEVEL env (debug, info, warn, error).
	logLevel := new(slog.LevelVar) // defaults to Info
	switch os.Getenv("LOG_LEVEL") {
	case "debug":
		logLevel.Set(slog.LevelDebug)
	case "warn":
		logLevel.Set(slog.LevelWarn)
	case "error":
		logLevel.Set(slog.LevelError)
	}
	slog.SetDefault(slog.New(slog.NewTextHandler(os.Stderr, &slog.HandlerOptions{Level: logLevel})))

	ctx, stop := signal.NotifyContext(context.Background(), os.Interrupt)
	defer stop()

	dbURL := envOr("DATABASE_URL", "postgres://localhost:5432/changelogue?sslmode=disable")
	addr := envOr("LISTEN_ADDR", ":8080")
	noAuth := os.Getenv("NO_AUTH") == "true"

	githubClientID := os.Getenv("GITHUB_CLIENT_ID")
	githubClientSecret := os.Getenv("GITHUB_CLIENT_SECRET")
	allowedUsers := os.Getenv("ALLOWED_GITHUB_USERS")
	allowedOrgs := os.Getenv("ALLOWED_GITHUB_ORGS")
	sessionSecret := os.Getenv("SESSION_SECRET")
	secureCookies := os.Getenv("SECURE_COOKIES") != "false"

	// Database
	pool, err := db.NewPool(ctx, dbURL)
	if err != nil {
		slog.Error("database connection failed", "err", err)
		os.Exit(1)
	}
	defer pool.Close()

	if err := db.RunMigrations(ctx, pool); err != nil {
		slog.Error("migrations failed", "err", err)
		os.Exit(1)
	}

	// API & routing store (created before River so we can register workers)
	// The river client is set to nil initially; TriggerAgentRun (which needs it)
	// won't be called until the server is up and the client is set below.
	pgStore := api.NewPgStore(pool, nil)

	// Auth setup
	allowlist := auth.NewAllowlist(allowedUsers, allowedOrgs)
	if !noAuth && !allowlist.HasEntries() {
		slog.Error("ALLOWED_GITHUB_USERS or ALLOWED_GITHUB_ORGS must be set when auth is enabled")
		os.Exit(1)
	}
	if !noAuth && sessionSecret == "" {
		slog.Error("SESSION_SECRET must be set when auth is enabled")
		os.Exit(1)
	}
	if !noAuth && (githubClientID == "" || githubClientSecret == "") {
		slog.Error("GITHUB_CLIENT_ID and GITHUB_CLIENT_SECRET must be set when auth is enabled")
		os.Exit(1)
	}

	sessionStore := auth.NewSessionStore(pool, sessionSecret)
	stateStore := auth.NewStateStore(1000, 10*time.Minute)

	oauthHandler := &auth.OAuthHandler{
		ClientID:     githubClientID,
		ClientSecret: githubClientSecret,
		Pool:         pool,
		Sessions:     sessionStore,
		States:       stateStore,
		Allowlist:    allowlist,
		SecureCookie: secureCookies,
		FrontendURL:  os.Getenv("FRONTEND_URL"),
		HTTPClient:   http.DefaultClient,
	}

	// Register River workers
	workers := river.NewWorkers()
	notifyWorker := routing.NewNotifyWorker(pgStore, os.Getenv("PUBLIC_URL"))
	river.AddWorker(workers, notifyWorker)

	// Agent worker: requires an LLM API key. If unavailable, agent jobs
	// will remain in the queue until the key is configured and the server
	// is restarted.
	llmProvider := envOr("LLM_PROVIDER", "gemini")
	llmModelDefault := "gemini-2.5-flash"
	if llmProvider == "openai" {
		llmModelDefault = "gpt-5.2"
	}
	llmConfig := agentpkg.LLMConfig{
		Provider:      llmProvider,
		Model:         envOr("LLM_MODEL", llmModelDefault),
		GoogleAPIKey:  os.Getenv("GOOGLE_API_KEY"),
		OpenAIAPIKey:  os.Getenv("OPENAI_API_KEY"),
		OpenAIBaseURL: os.Getenv("OPENAI_BASE_URL"),
	}
	agentOrchestrator, err := agentpkg.NewOrchestrator(pgStore, llmConfig, os.Getenv("PUBLIC_URL"))
	if err != nil {
		slog.Warn("agent orchestrator not available — agent jobs will not be processed", "err", err)
	} else {
		agentWorker := agentpkg.NewAgentWorker(agentOrchestrator, pgStore)
		river.AddWorker(workers, agentWorker)
		slog.Info("agent worker registered")
	}

	// Scan worker: requires LLM for dependency extraction
	scanScanner := onboard.NewScanner(http.DefaultClient, "", "")
	var scanExtractor *onboard.DependencyExtractor
	extractorCfg := onboard.ExtractorConfig{
		Provider:      llmConfig.Provider,
		Model:         llmConfig.Model,
		GoogleAPIKey:  llmConfig.GoogleAPIKey,
		OpenAIAPIKey:  llmConfig.OpenAIAPIKey,
		OpenAIBaseURL: llmConfig.OpenAIBaseURL,
	}
	ext, err := onboard.NewDependencyExtractor(ctx, extractorCfg)
	if err != nil {
		slog.Warn("dependency extractor not available", "err", err)
	} else {
		scanExtractor = ext
	}
	scanWorker := onboard.NewScanWorker(pgStore, scanScanner, scanExtractor, pool)
	river.AddWorker(workers, scanWorker)
	slog.Info("scan worker registered")

	riverClient, err := queue.NewRiverClient(pool, workers)
	if err != nil {
		slog.Error("river client failed", "err", err)
		os.Exit(1)
	}

	// Now that the river client exists, set it on the existing pgStore so that
	// all holders (including NotifyWorker) can enqueue agent jobs.
	pgStore.SetRiverClient(riverClient)

	if err := riverClient.Start(ctx); err != nil {
		slog.Error("river start failed", "err", err)
		os.Exit(1)
	}

	// Ingestion layer
	ingestionStore := ingestion.NewPgStore(pool, riverClient)
	svc := ingestion.NewService(ingestionStore)

	loader := ingestion.NewSourceLoader(pool, http.DefaultClient)
	orch := ingestion.NewOrchestrator(svc, loader, pool, 5*time.Minute)

	broadcaster := api.NewBroadcaster()

	mux := http.NewServeMux()

	// Serve frontend static export if available
	if info, err := os.Stat("web/out"); err == nil && info.IsDir() {
		api.RegisterFrontend(mux, "web/out")
		slog.Info("serving frontend from web/out")
	}

	// Register all API v1 routes
	api.RegisterRoutes(mux, api.Dependencies{
		DB:                    pool,
		ProjectsStore:         pgStore,
		ReleasesStore:         pgStore,
		SubscriptionsStore:    pgStore,
		SourcesStore:          pgStore,
		ChannelsStore:         pgStore,
		ContextSourcesStore:   pgStore,
		SemanticReleasesStore: pgStore,
		AgentStore:            pgStore,
		TodosStore:            pgStore,
		OnboardStore:          pgStore,
		PublicURL:             os.Getenv("PUBLIC_URL"),
		KeyStore:              pgStore,
		SessionValidator:      sessionStore,
		HealthChecker:         pgStore,
		Broadcaster:           broadcaster,
		NoAuth:                noAuth,
		IngestionService:      svc,
		HTTPClient:            http.DefaultClient,
	})

	api.RegisterAuthRoutes(mux, oauthHandler, noAuth, os.Getenv("FRONTEND_URL"))

	srv := &http.Server{Addr: addr, Handler: api.CORS(mux)}

	// Start polling in background
	go orch.Run(ctx)

	// Start PostgreSQL LISTEN/NOTIFY → SSE bridge
	go api.ListenForNotifications(ctx, pool, broadcaster)

	// Start session cleanup loop
	go sessionStore.RunCleanupLoop(ctx)

	// Start HTTP server
	go func() {
		slog.Info("server starting", "addr", srv.Addr)
		if err := srv.ListenAndServe(); err != http.ErrServerClosed {
			slog.Error("server error", "err", err)
		}
	}()

	<-ctx.Done()
	slog.Info("shutting down")

	shutdownCtx, cancel := context.WithTimeout(context.Background(), 10*time.Second)
	defer cancel()
	riverClient.Stop(shutdownCtx)
	srv.Shutdown(shutdownCtx)
}

func envOr(key, fallback string) string {
	if v := os.Getenv(key); v != "" {
		return v
	}
	return fallback
}

package queue

import (
	"github.com/jackc/pgx/v5"
	"github.com/jackc/pgx/v5/pgxpool"
	"github.com/riverqueue/river"
	"github.com/riverqueue/river/riverdriver/riverpgxv5"
)

// NewRiverClient creates a River client backed by the given pgx pool.
// Pass nil workers to create an insert-only client (no job processing).
func NewRiverClient(pool *pgxpool.Pool, workers *river.Workers) (*river.Client[pgx.Tx], error) {
	config := &river.Config{}
	if workers != nil {
		config.Workers = workers
		config.Queues = map[string]river.QueueConfig{
			river.QueueDefault: {MaxWorkers: 100},
		}
	}
	return river.NewClient(riverpgxv5.New(pool), config)
}

package agent

import (
	"context"
	"encoding/json"
	"fmt"
	"log/slog"
	"time"

	"github.com/riverqueue/river"
	"github.com/sentioxyz/changelogue/internal/models"
	"github.com/sentioxyz/changelogue/internal/queue"
)

// AgentWorker is a River worker that processes AgentJobArgs by running the
// LLM agent orchestrator. When a job is dequeued, it loads the corresponding
// agent run from the store and delegates to Orchestrator.RunAgent.
type AgentWorker struct {
	river.WorkerDefaults[queue.AgentJobArgs]
	orchestrator *Orchestrator
	store        OrchestratorStore
}

// NewAgentWorker creates a new AgentWorker backed by the given orchestrator
// and store.
func NewAgentWorker(orchestrator *Orchestrator, store OrchestratorStore) *AgentWorker {
	return &AgentWorker{
		orchestrator: orchestrator,
		store:        store,
	}
}

// Timeout overrides River's default 60-second job timeout. Agent runs involve
// multiple LLM round-trips (root agent + sub-agents), each of which can take
// 10-30 seconds, so we allow 5 minutes total.
func (w *AgentWorker) Timeout(_ *river.Job[queue.AgentJobArgs]) time.Duration {
	return 5 * time.Minute
}

// Work processes a single AgentJobArgs job. It loads the agent run from the
// database and runs the LLM agent through the orchestrator. If the project
// has WaitForAllSources enabled and not all sources have the target version,
// the job is snoozed for 5 minutes via river.JobSnooze.
func (w *AgentWorker) Work(ctx context.Context, job *river.Job[queue.AgentJobArgs]) error {
	slog.Info("agent worker picked up job",
		"job_id", job.ID,
		"agent_run_id", job.Args.AgentRunID,
		"attempt", job.Attempt,
	)

	run, err := w.store.GetAgentRun(ctx, job.Args.AgentRunID)
	if err != nil {
		slog.Error("agent worker failed to load agent run",
			"job_id", job.ID,
			"agent_run_id", job.Args.AgentRunID,
			"err", err,
		)
		return fmt.Errorf("get agent run: %w", err)
	}

	// Check multi-source waiting: if the run has a version and the project
	// has WaitForAllSources enabled, verify all sources have reported a
	// release for the target version before running the agent.
	if run.Version != "" {
		project, err := w.store.GetProject(ctx, run.ProjectID)
		if err != nil {
			slog.Error("agent worker failed to load project",
				"job_id", job.ID,
				"project_id", run.ProjectID,
				"err", err,
			)
			return fmt.Errorf("get project: %w", err)
		}

		var rules models.AgentRules
		if len(project.AgentRules) > 0 {
			if err := json.Unmarshal(project.AgentRules, &rules); err != nil {
				slog.Warn("agent worker: failed to unmarshal agent rules, proceeding without wait",
					"project_id", run.ProjectID, "err", err)
			}
		}

		if rules.WaitForAllSources {
			ready, err := w.orchestrator.checkAllSourcesReady(ctx, run.ProjectID, run.Version)
			if err != nil {
				slog.Error("agent worker: error checking source readiness",
					"job_id", job.ID,
					"project_id", run.ProjectID,
					"version", run.Version,
					"err", err,
				)
				return fmt.Errorf("check all sources ready: %w", err)
			}
			if !ready {
				// After maxWaitAttempts (12 × 5min = ~1 hour), proceed
				// with partial data rather than waiting forever.
				const maxWaitAttempts = 12
				if job.Attempt >= maxWaitAttempts {
					slog.Warn("agent worker: max wait attempts reached, proceeding with partial data",
						"job_id", job.ID,
						"project_id", run.ProjectID,
						"version", run.Version,
						"attempts", job.Attempt,
					)
				} else {
					slog.Info("agent worker: not all sources ready, snoozing",
						"job_id", job.ID,
						"project_id", run.ProjectID,
						"version", run.Version,
						"attempt", job.Attempt,
					)
					if err := w.store.UpdateAgentRunStatus(ctx, run.ID, "waiting"); err != nil {
						slog.Error("failed to set waiting status", "err", err)
					}
					return river.JobSnooze(5 * time.Minute)
				}
			}
		}
	}

	slog.Info("agent worker starting run",
		"job_id", job.ID,
		"agent_run_id", run.ID,
		"project_id", run.ProjectID,
		"trigger", run.Trigger,
	)

	if err := w.orchestrator.RunAgent(ctx, run); err != nil {
		slog.Error("agent worker run failed",
			"job_id", job.ID,
			"agent_run_id", run.ID,
			"project_id", run.ProjectID,
			"err", err,
		)
		return err
	}

	slog.Info("agent worker run completed",
		"job_id", job.ID,
		"agent_run_id", run.ID,
		"project_id", run.ProjectID,
	)
	return nil
}

package db

import (
	"context"
	"fmt"

	"github.com/jackc/pgx/v5/pgxpool"
	"github.com/riverqueue/river/riverdriver/riverpgxv5"
	"github.com/riverqueue/river/rivermigrate"
)

const schema = `
-- Tracked software projects (the central entity)
CREATE TABLE IF NOT EXISTS projects (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    name VARCHAR(100) NOT NULL UNIQUE,
    description TEXT,
    agent_prompt TEXT,
    agent_rules JSONB,
    created_at TIMESTAMPTZ DEFAULT NOW(),
    updated_at TIMESTAMPTZ DEFAULT NOW()
);

-- Configured ingestion sources (polling-based: GitHub, Docker Hub)
CREATE TABLE IF NOT EXISTS sources (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    project_id UUID NOT NULL REFERENCES projects(id) ON DELETE CASCADE,
    provider VARCHAR(50) NOT NULL,
    repository VARCHAR(255) NOT NULL,
    poll_interval_seconds INT DEFAULT 86400,
    enabled BOOLEAN DEFAULT true,
    config JSONB,
    last_polled_at TIMESTAMPTZ,
    last_error TEXT,
    created_at TIMESTAMPTZ DEFAULT NOW(),
    updated_at TIMESTAMPTZ DEFAULT NOW(),
    UNIQUE(provider, repository)
);

-- Context sources (read-only references for agent research)
CREATE TABLE IF NOT EXISTS context_sources (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    project_id UUID NOT NULL REFERENCES projects(id) ON DELETE CASCADE,
    type VARCHAR(50) NOT NULL,
    name VARCHAR(100) NOT NULL,
    config JSONB NOT NULL,
    created_at TIMESTAMPTZ DEFAULT NOW(),
    updated_at TIMESTAMPTZ DEFAULT NOW()
);

-- Source-level releases (detected from polling sources)
CREATE TABLE IF NOT EXISTS releases (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    source_id UUID NOT NULL REFERENCES sources(id) ON DELETE CASCADE,
    version VARCHAR(100) NOT NULL,
    raw_data JSONB,
    released_at TIMESTAMPTZ,
    created_at TIMESTAMPTZ DEFAULT NOW(),
    UNIQUE(source_id, version)
);

-- Project-level semantic releases (AI-generated, correlating source releases)
CREATE TABLE IF NOT EXISTS semantic_releases (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    project_id UUID NOT NULL REFERENCES projects(id) ON DELETE CASCADE,
    version VARCHAR(100) NOT NULL,
    report JSONB,
    status VARCHAR(50) NOT NULL DEFAULT 'pending',
    error TEXT,
    created_at TIMESTAMPTZ DEFAULT NOW(),
    completed_at TIMESTAMPTZ,
    UNIQUE(project_id, version)
);

-- Join table: which source releases compose a semantic release
CREATE TABLE IF NOT EXISTS semantic_release_sources (
    semantic_release_id UUID NOT NULL REFERENCES semantic_releases(id) ON DELETE CASCADE,
    release_id UUID NOT NULL REFERENCES releases(id) ON DELETE CASCADE,
    PRIMARY KEY (semantic_release_id, release_id)
);

-- Notification channels (standalone)
CREATE TABLE IF NOT EXISTS notification_channels (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    name VARCHAR(100) NOT NULL,
    type VARCHAR(50) NOT NULL,
    config JSONB NOT NULL,
    created_at TIMESTAMPTZ DEFAULT NOW(),
    updated_at TIMESTAMPTZ DEFAULT NOW()
);

-- Subscriptions: two types (source releases and semantic releases)
CREATE TABLE IF NOT EXISTS subscriptions (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    channel_id UUID NOT NULL REFERENCES notification_channels(id) ON DELETE CASCADE,
    type VARCHAR(50) NOT NULL CHECK (type IN ('source_release', 'semantic_release')),
    source_id UUID REFERENCES sources(id) ON DELETE CASCADE,
    project_id UUID REFERENCES projects(id) ON DELETE CASCADE,
    version_filter TEXT,
    created_at TIMESTAMPTZ DEFAULT NOW(),
    CHECK (
        (type = 'source_release'   AND source_id  IS NOT NULL AND project_id IS NULL) OR
        (type = 'semantic_release' AND project_id IS NOT NULL AND source_id  IS NULL)
    )
);

-- Agent runs (scoped to project)
CREATE TABLE IF NOT EXISTS agent_runs (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    project_id UUID NOT NULL REFERENCES projects(id) ON DELETE CASCADE,
    semantic_release_id UUID REFERENCES semantic_releases(id) ON DELETE SET NULL,
    trigger VARCHAR(100) NOT NULL,
    status VARCHAR(50) NOT NULL DEFAULT 'pending',
    prompt_used TEXT,
    error TEXT,
    started_at TIMESTAMPTZ,
    completed_at TIMESTAMPTZ,
    created_at TIMESTAMPTZ DEFAULT NOW()
);

ALTER TABLE agent_runs ADD COLUMN IF NOT EXISTS version VARCHAR(100);

-- API authentication keys
CREATE TABLE IF NOT EXISTS api_keys (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    name VARCHAR(100) NOT NULL,
    key_hash VARCHAR(64) NOT NULL UNIQUE,
    key_prefix VARCHAR(12) NOT NULL,
    created_at TIMESTAMPTZ DEFAULT NOW(),
    last_used_at TIMESTAMPTZ
);

-- Trigger for SSE: notify on new releases
CREATE OR REPLACE FUNCTION notify_release_created() RETURNS trigger AS $$
BEGIN
    PERFORM pg_notify('release_events', json_build_object('type', 'release', 'id', NEW.id)::text);
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS release_created_trigger ON releases;
CREATE TRIGGER release_created_trigger
    AFTER INSERT ON releases
    FOR EACH ROW EXECUTE FUNCTION notify_release_created();

-- Trigger for SSE: notify on semantic release completion
CREATE OR REPLACE FUNCTION notify_semantic_release() RETURNS trigger AS $$
BEGIN
    IF NEW.status = 'completed' AND (OLD IS NULL OR OLD.status != 'completed') THEN
        PERFORM pg_notify('release_events', json_build_object('type', 'semantic_release', 'id', NEW.id)::text);
    END IF;
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS semantic_release_trigger ON semantic_releases;
CREATE TRIGGER semantic_release_trigger
    AFTER INSERT OR UPDATE ON semantic_releases
    FOR EACH ROW EXECUTE FUNCTION notify_semantic_release();

-- Release TODOs (acknowledge/resolve tracking)
CREATE TABLE IF NOT EXISTS release_todos (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    release_id UUID REFERENCES releases(id) ON DELETE CASCADE,
    semantic_release_id UUID REFERENCES semantic_releases(id) ON DELETE CASCADE,
    status VARCHAR(20) NOT NULL DEFAULT 'pending',
    created_at TIMESTAMPTZ DEFAULT NOW(),
    acknowledged_at TIMESTAMPTZ,
    resolved_at TIMESTAMPTZ,
    CHECK (
        (release_id IS NOT NULL AND semantic_release_id IS NULL) OR
        (release_id IS NULL AND semantic_release_id IS NOT NULL)
    )
);
CREATE UNIQUE INDEX IF NOT EXISTS idx_release_todos_release_id ON release_todos(release_id) WHERE release_id IS NOT NULL;
CREATE UNIQUE INDEX IF NOT EXISTS idx_release_todos_semantic_release_id ON release_todos(semantic_release_id) WHERE semantic_release_id IS NOT NULL;

-- Onboarding scans (GitHub repo dependency detection)
CREATE TABLE IF NOT EXISTS onboard_scans (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    repo_url TEXT NOT NULL,
    status VARCHAR(50) NOT NULL DEFAULT 'pending',
    results JSONB,
    error TEXT,
    created_at TIMESTAMPTZ DEFAULT NOW(),
    started_at TIMESTAMPTZ,
    completed_at TIMESTAMPTZ
);

-- Authenticated users (GitHub OAuth)
CREATE TABLE IF NOT EXISTS users (
    id              UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    github_id       BIGINT NOT NULL UNIQUE,
    github_login    VARCHAR(100) NOT NULL,
    name            VARCHAR(200),
    avatar_url      TEXT,
    created_at      TIMESTAMPTZ DEFAULT NOW(),
    updated_at      TIMESTAMPTZ DEFAULT NOW()
);

-- User sessions (server-side, referenced by HttpOnly cookie)
CREATE TABLE IF NOT EXISTS sessions (
    id          UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    user_id     UUID NOT NULL REFERENCES users(id) ON DELETE CASCADE,
    expires_at  TIMESTAMPTZ NOT NULL,
    created_at  TIMESTAMPTZ DEFAULT NOW()
);
CREATE INDEX IF NOT EXISTS idx_sessions_user_id ON sessions(user_id);
CREATE INDEX IF NOT EXISTS idx_sessions_expires_at ON sessions(expires_at);
`

// RunMigrations applies River's schema and the application schema. Idempotent — safe to call on every startup.
func RunMigrations(ctx context.Context, pool *pgxpool.Pool) error {
	migrator, err := rivermigrate.New(riverpgxv5.New(pool), nil)
	if err != nil {
		return fmt.Errorf("create river migrator: %w", err)
	}
	if _, err := migrator.Migrate(ctx, rivermigrate.DirectionUp, nil); err != nil {
		return fmt.Errorf("river migrations: %w", err)
	}

	if _, err := pool.Exec(ctx, schema); err != nil {
		return fmt.Errorf("app migrations: %w", err)
	}

	// Migrate existing subscription type values: source→source_release, project→semantic_release.
	// Drop old CHECK constraints first (both the named type check and the unnamed
	// composite check referencing old values), then UPDATE data, then re-add constraints.
	if _, err := pool.Exec(ctx, `
		ALTER TABLE subscriptions DROP CONSTRAINT IF EXISTS subscriptions_type_check;
		ALTER TABLE subscriptions DROP CONSTRAINT IF EXISTS subscriptions_check;
		UPDATE subscriptions SET type = 'source_release' WHERE type = 'source';
		UPDATE subscriptions SET type = 'semantic_release' WHERE type = 'project';
		ALTER TABLE subscriptions ADD CONSTRAINT subscriptions_type_check CHECK (type IN ('source_release', 'semantic_release'));
		ALTER TABLE subscriptions ADD CONSTRAINT subscriptions_check CHECK (
			(type = 'source_release'   AND source_id IS NOT NULL AND project_id IS NULL) OR
			(type = 'semantic_release' AND project_id IS NOT NULL AND source_id IS NULL)
		);
	`); err != nil {
		return fmt.Errorf("subscription type migration: %w", err)
	}

	if _, err := pool.Exec(ctx, `
		ALTER TABLE sources ADD COLUMN IF NOT EXISTS version_filter_include TEXT;
		ALTER TABLE sources ADD COLUMN IF NOT EXISTS version_filter_exclude TEXT;
	`); err != nil {
		return fmt.Errorf("source version filter migration: %w", err)
	}

	if _, err := pool.Exec(ctx, `
		ALTER TABLE sources ADD COLUMN IF NOT EXISTS exclude_prereleases BOOLEAN DEFAULT false;
	`); err != nil {
		return fmt.Errorf("source exclude_prereleases migration: %w", err)
	}
	return nil
}

