    30→// NotifyWorker is a River worker that processes NotifyJobArgs.
    31→// It looks up the release, finds all source-level subscriptions, resolves
    32→// the notification channel for each, and dispatches via the appropriate sender.
    33→// After sending notifications, it checks the project's agent rules and
    34→// auto-triggers an agent run if the version criteria are met.
    35→type NotifyWorker struct {
    36→	river.WorkerDefaults[queue.NotifyJobArgs]
    37→	store     NotifyStore
    38→	senders   map[string]Sender
    39→	publicURL string // base URL for internal Changelogue links (e.g. "https://changelogue.example.com")
    40→}
    41→
    42→// NewSenders returns the default sender map for all notification channel types.
    43→func NewSenders() map[string]Sender {
    44→	return map[string]Sender{
    45→		"webhook": &WebhookSender{Client: &http.Client{Timeout: 10 * time.Second}},
    46→		"slack":   &SlackSender{Client: &http.Client{Timeout: 10 * time.Second}},
    47→		"discord": &DiscordSender{Client: &http.Client{Timeout: 10 * time.Second}},
    48→		"email":   &EmailSender{},
    49→	}
    50→}
    51→
    52→// NewNotifyWorker creates a NotifyWorker with default senders for webhook, Slack, and Discord.
    53→func NewNotifyWorker(store NotifyStore, publicURL string) *NotifyWorker {
    54→	return &NotifyWorker{
    55→		store:     store,
    56→		senders:   NewSenders(),
    57→		publicURL: strings.TrimRight(publicURL, "/"),
    58→	}
    59→}
    60→
    61→// VersionPassesFilter returns true if the version string passes the source's
    62→// include/exclude regex filters. When both are nil the version always passes.
    63→func VersionPassesFilter(version string, include, exclude *string) bool {
    64→	if include != nil && *include != "" {
    65→		matched, err := regexp.MatchString(*include, version)
    66→		if err != nil || !matched {
    67→			return false
    68→		}
    69→	}
    70→	if exclude != nil && *exclude != "" {
    71→		matched, err := regexp.MatchString(*exclude, version)
    72→		if err != nil || matched {
    73→			return false
    74→		}
    75→	}
    76→	return true
    77→}
    78→
    79→// Work processes a notify job: fetches the release, resolves subscriptions,
    80→// sends notifications to all matching channels, and checks agent rules to
    81→// auto-trigger agent runs when version criteria are met.
    82→func (w *NotifyWorker) Work(ctx context.Context, job *river.Job[queue.NotifyJobArgs]) error {
    83→	release, err := w.store.GetRelease(ctx, job.Args.ReleaseID)
    84→	if err != nil {
    85→		return fmt.Errorf("get release: %w", err)
    86→	}
    87→
    88→	// Check source version filters — skip entirely if filtered out.
    89→	source, err := w.store.GetSource(ctx, job.Args.SourceID)
    90→	if err != nil {
    91→		return fmt.Errorf("get source: %w", err)
    92→	}
    93→	if !VersionPassesFilter(release.Version, source.VersionFilterInclude, source.VersionFilterExclude) {
    94→		slog.Debug("release filtered by version filter", "version", release.Version, "source_id", job.Args.SourceID)
    95→		return nil
    96→	}
    97→
    98→	// Check exclude_prereleases — skip if source excludes prereleases and this is one.
    99→	if source.ExcludePrereleases {
   100→		var rawData map[string]interface{}
   101→		if err := json.Unmarshal(release.RawData, &rawData); err == nil {
   102→			if prerelease, _ := rawData["prerelease"].(string); prerelease == "true" {
   103→				slog.Debug("release filtered by exclude_prereleases", "version", release.Version, "source_id", job.Args.SourceID)
   104→				return nil
   105→			}
   106→		}
   107→	}
   108→
   109→	// Create a TODO for this release (idempotent — safe for retries).
   110→	todoID, todoErr := w.store.CreateReleaseTodo(ctx, release.ID)
   111→	if todoErr != nil {
   112→		slog.Error("create release todo failed", "release_id", release.ID, "err", todoErr)
   113→		// Continue — notification delivery is primary responsibility.
   114→	}
   115→
   116→	subs, err := w.store.ListSourceSubscriptions(ctx, job.Args.SourceID)
   117→	if err != nil {
   118→		return fmt.Errorf("list subscriptions: %w", err)
   119→	}
   120→
   121→	for _, sub := range subs {
   122→		ch, err := w.store.GetChannel(ctx, sub.ChannelID)
   123→		if err != nil {
   124→			slog.Error("get channel failed", "channel_id", sub.ChannelID, "err", err)
   125→			continue
   126→		}
   127→
   128→		sender, ok := w.senders[ch.Type]
   129→		if !ok {
   130→			slog.Warn("unknown channel type", "type", ch.Type)
   131→			continue
   132→		}
   133→
   134→		// Build title with project name if available.
   135→		title := release.Version
   136→		if release.ProjectName != "" {
   137→			title = release.ProjectName
   138→		}
   139→
   140→		msg := Notification{
   141→			Title:       title,
   142→			Body:        string(release.RawData),
   143→			Version:     release.Version,
   144→			ProjectName: release.ProjectName,
   145→			Provider:    release.Provider,
   146→			Repository:  release.Repository,
   147→			SourceURL:   ProviderURL(release.Provider, release.Repository, release.Version),
   148→		}
   149→		if w.publicURL != "" {
   150→			msg.ReleaseURL = fmt.Sprintf("%s/releases/%s", w.publicURL, release.ID)
   151→		}
   152→		if todoID != "" {
   153→			msg.TodoID = todoID
   154→			msg.PublicURL = w.publicURL
   155→		}
   156→
   157→		if err := sender.Send(ctx, ch, msg); err != nil {
   158→			slog.Error("send notification failed", "channel", ch.Name, "err", err)
   159→		}
   160→	}
   161→
   162→	// Check agent rules and auto-trigger if criteria are met.
   163→	w.checkAgentRules(ctx, release, source)
   164→
   165→	return nil
   166→}
   167→
   168→// checkAgentRules evaluates the project's agent rules against the new release
   169→// and the previous release for this source. If any rule matches, an agent run
   170→// is enqueued. Errors are logged but do not fail the job — notification delivery
   171→// is the primary responsibility.
   172→func (w *NotifyWorker) checkAgentRules(ctx context.Context, release *models.Release, source *models.Source) {
   173→	project, err := w.store.GetProject(ctx, source.ProjectID)
   174→	if err != nil {
   175→		slog.Error("get project for agent rules", "project_id", source.ProjectID, "err", err)
   176→		return
   177→	}
   178→
   179→	// Parse the project's agent_rules JSON.
   180→	var rules models.AgentRules
   181→	if len(project.AgentRules) > 0 {
   182→		if err := json.Unmarshal(project.AgentRules, &rules); err != nil {
   183→			slog.Error("unmarshal agent rules", "project_id", project.ID, "err", err)
   184→			return
   185→		}
   186→	}
   187→
   188→	// Determine the previous version for comparison.
   189→	var previousVersion string
   190→	prev, err := w.store.GetPreviousRelease(ctx, source.ID, release.Version)
   191→	if err != nil {
   192→		slog.Error("get previous release for agent rules", "source_id", source.ID, "err", err)
   193→		return
   194→	}
   195→	if prev != nil {
   196→		previousVersion = prev.Version
   197→	}
   198→
   199→	if CheckAgentRules(&rules, release.Version, previousVersion) {
   200→		trigger := fmt.Sprintf("auto:version:%s", release.Version)
   201→		if err := w.store.EnqueueAgentRun(ctx, source.ProjectID, trigger, release.Version); err != nil {
   202→			slog.Error("enqueue agent run", "project_id", source.ProjectID, "err", err)
   203→		} else {
   204→			slog.Info("agent run triggered by version rules",
   205→				"project_id", source.ProjectID,
   206→				"version", release.Version,
   207→				"previous_version", previousVersion,
   208→			)
   209→		}
   210→	}
   211→}
