   707→   707→package gate
   708→   708→
   709→   709→import (
   710→   710→	"context"
   711→   711→	"encoding/json"
   712→   712→	"fmt"
   713→   713→	"log/slog"
   714→   714→
   715→   715→	"github.com/jackc/pgx/v5"
   716→   716→	"github.com/riverqueue/river"
   717→   717→	"github.com/sentioxyz/changelogue/internal/models"
   718→   718→	"github.com/sentioxyz/changelogue/internal/queue"
   719→   719→)
   720→   720→
   721→   721→// GateCheckWorker evaluates release gate readiness when a new release is ingested.
   722→   722→type GateCheckWorker struct {
   723→   723→	river.WorkerDefaults[queue.GateCheckJobArgs]
   724→   724→	store       GateStore
   725→   725→	riverClient *river.Client[pgx.Tx] // for enqueuing NL eval jobs
   726→   726→}
   727→   727→
   728→   728→// NewGateCheckWorker creates a new GateCheckWorker.
   729→   729→func NewGateCheckWorker(store GateStore, riverClient *river.Client[pgx.Tx]) *GateCheckWorker {
   730→   730→	return &GateCheckWorker{store: store, riverClient: riverClient}
   731→   731→}
   732→   732→
   733→   733→func (w *GateCheckWorker) Work(ctx context.Context, job *river.Job[queue.GateCheckJobArgs]) error {
   734→   734→	// Load gate config via source → project lookup.
   735→   735→	gate, err := w.store.GetReleaseGateBySource(ctx, job.Args.SourceID)
   736→   736→	if err != nil {
   737→   737→		return fmt.Errorf("get release gate: %w", err)
   738→   738→	}
   739→   739→	if gate == nil || !gate.Enabled {
   740→   740→		return nil // no gate — no-op
   741→   741→	}
   742→   742→
   743→   743→	// Normalize the version.
   744→   744→	normalized := NormalizeVersionForSource(job.Args.Version, job.Args.SourceID, gate.VersionMapping)
   745→   745→
   746→   746→	slog.Info("gate check: evaluating",
   747→   747→		"source_id", job.Args.SourceID,
   748→   748→		"raw_version", job.Args.Version,
   749→   749→		"normalized", normalized,
   750→   750→		"project_id", gate.ProjectID,
   751→   751→	)
   752→   752→
   753→   753→	// Determine required sources: if gate.RequiredSources is empty, use all project sources.
   754→   754→	required := gate.RequiredSources
   755→   755→	if len(required) == 0 {
   756→   756→		sources, _, err := w.store.ListSourcesByProject(ctx, gate.ProjectID, 1, 1000)
   757→   757→		if err != nil {
   758→   758→			return fmt.Errorf("list sources: %w", err)
   759→   759→		}
   760→   760→		for _, s := range sources {
   761→   761→			required = append(required, s.ID)
   762→   762→		}
   763→   763→	}
   764→   764→
   765→   765→	// Upsert version readiness (atomic).
   766→   766→	vr, allMet, err := w.store.UpsertVersionReadiness(ctx, gate.ProjectID, normalized, job.Args.SourceID, required, gate.TimeoutHours)
   767→   767→	if err != nil {
   768→   768→		return fmt.Errorf("upsert version readiness: %w", err)
   769→   769→	}
   770→   770→
   771→   771→	// Record source_met event.
   772→   772→	sourceID := job.Args.SourceID
   773→   773→	details, _ := json.Marshal(map[string]interface{}{
   774→   774→		"raw_version":        job.Args.Version,
   775→   775→		"normalized_version": normalized,
   776→   776→		"sources_met":        len(vr.SourcesMet),
   777→   777→		"sources_required":   len(required),
   778→   778→	})
   779→   779→	_ = w.store.RecordGateEvent(ctx, vr.ID, gate.ProjectID, normalized, "source_met", &sourceID, details)
   780→   780→
   781→   781→	if !allMet {
   782→   782→		slog.Info("gate check: waiting for more sources",
   783→   783→			"project_id", gate.ProjectID,
   784→   784→			"version", normalized,
   785→   785→			"met", len(vr.SourcesMet),
   786→   786→			"required", len(required),
   787→   787→		)
   788→   788→		return nil
   789→   789→	}
   790→   790→
   791→   791→	// All structured rules pass. Check for NL rule.
   792→   792→	if gate.NLRule != "" {
   793→   793→		// Check if NL rule already passed from a previous evaluation.
   794→   794→		if vr.NLRulePassed != nil && *vr.NLRulePassed {
   795→   795→			// Already passed — open gate.
   796→   796→		} else {
   797→   797→			// Enqueue NL evaluation.
   798→   798→			if w.riverClient != nil {
   799→   799→				_, err := w.riverClient.Insert(ctx, queue.GateNLEvalJobArgs{
   800→   800→					VersionReadinessID: vr.ID,
   801→   801→					ProjectID:          gate.ProjectID,
   802→   802→					Version:            normalized,
   803→   803→				}, nil)
   804→   804→				if err != nil {
   805→   805→					slog.Error("gate check: failed to enqueue NL eval", "err", err)
   806→   806→				}
   807→   807→			}
   808→   808→			return nil // wait for NL eval
   809→   809→		}
   810→   810→	}
   811→   811→
   812→   812→	// Open the gate.
   813→   813→	opened, err := w.store.OpenGate(ctx, vr.ID, "ready")
   814→   814→	if err != nil {
   815→   815→		return fmt.Errorf("open gate: %w", err)
   816→   816→	}
   817→   817→	if !opened {
   818→   818→		return nil // already opened by another worker
   819→   819→	}
   820→   820→
   821→   821→	_ = w.store.RecordGateEvent(ctx, vr.ID, gate.ProjectID, normalized, "gate_opened", nil, nil)
   822→   822→
   823→   823→	// Trigger agent.
   824→   824→	return w.triggerAgent(ctx, gate.ProjectID, normalized, vr.ID)
   825→   825→}
   826→   826→
   827→   827→// triggerAgent checks agent rules and enqueues an agent run.
   828→   828→func (w *GateCheckWorker) triggerAgent(ctx context.Context, projectID, version, readinessID string) error {
   829→   829→	trigger := fmt.Sprintf("gate:version:%s", version)
   830→   830→	if err := w.store.EnqueueAgentRun(ctx, projectID, trigger, version); err != nil {
   831→   831→		slog.Error("gate: failed to enqueue agent run", "project_id", projectID, "version", version, "err", err)
   832→   832→		return nil // don't fail the gate job
   833→   833→	}
   834→   834→
   835→   835→	_ = w.store.MarkAgentTriggered(ctx, readinessID)
   836→   836→
   837→   837→	details, _ := json.Marshal(map[string]interface{}{"partial": false})
   838→   838→	_ = w.store.RecordGateEvent(ctx, readinessID, projectID, version, "agent_triggered", nil, details)
   839→   839→
   840→   840→	slog.Info("gate: agent triggered", "project_id", projectID, "version", version)
   841→   841→	return nil
   842→   842→}
   843→   843→```
