   942→   942→
   943→   943→// GateTimeoutWorker is a periodic River worker that sweeps expired pending gates.
   944→   944→type GateTimeoutWorker struct {
   945→   945→	river.WorkerDefaults[queue.GateTimeoutJobArgs]
   946→   946→	store GateStore
   947→   947→}
   948→   948→
   949→   949→// NewGateTimeoutWorker creates a new GateTimeoutWorker.
   950→   950→func NewGateTimeoutWorker(store GateStore) *GateTimeoutWorker {
   951→   951→	return &GateTimeoutWorker{store: store}
   952→   952→}
   953→   953→
   954→   954→func (w *GateTimeoutWorker) Work(ctx context.Context, _ *river.Job[queue.GateTimeoutJobArgs]) error {
   955→   955→	expired, err := w.store.ListExpiredGates(ctx, 100)
   956→   956→	if err != nil {
   957→   957→		return fmt.Errorf("list expired gates: %w", err)
   958→   958→	}
   959→   959→
   960→   960→	for _, vr := range expired {
   961→   961→		opened, err := w.store.OpenGate(ctx, vr.ID, "timed_out")
   962→   962→		if err != nil {
   963→   963→			slog.Error("gate timeout: failed to open gate", "readiness_id", vr.ID, "err", err)
   964→   964→			continue
   965→   965→		}
   966→   966→		if !opened {
   967→   967→			continue // already opened
   968→   968→		}
   969→   969→
   970→   970→		details, _ := json.Marshal(map[string]interface{}{
   971→   971→			"sources_missing": vr.SourcesMissing,
   972→   972→		})
   973→   973→		_ = w.store.RecordGateEvent(ctx, vr.ID, vr.ProjectID, vr.Version, "gate_timed_out", nil, details)
   974→   974→
